+
+    @Test
+    // (((a ^ b) << v) + y) >>> 19  =>  ((a ^ b) + (y >>> 19)) & mask
+    // v is only known to be 19 after loop optimization, so LShiftI's shift count
+    // changes mid-IGVN. URShiftI must be notified through AddI (Case 2).
+    @IR(counts = {IRNode.LSHIFT_I,  "0",
+                  IRNode.URSHIFT_I, "1",
+                  IRNode.AND_I,     "1"})
+    static int testIComputedX(int a, int b, int y) {
+        int u = 19;
+        int v = 0;
+        do {
+            u--;
+            v++;
+        } while (u > 0);
+        return (((a ^ b) << v) + y) >>> 19;
+    }
+
+    @Test
+    // (((a ^ b) << v) + y) >>> 19  =>  ((a ^ b) + (y >>> 19)) & mask
+    // v is only known to be 19 after loop optimization, so LShiftL's shift count
+    // changes mid-IGVN. URShiftL must be notified through AddL (Case 2).
+    @IR(counts = {IRNode.LSHIFT_L,  "0",
+                  IRNode.URSHIFT_L, "1",
+                  IRNode.AND_L,     "1"})
+    static long testLComputedX(long a, long b, long y) {
+        int u = 19;
+        int v = 0;
+        do {
+            u--;
+            v++;
+        } while (u > 0);
+        return (((a ^ b) << v) + y) >>> 19;
+    }
